import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "b940bedc-3d67-45b0-8709-b3d070e5e454";

  // Probe first: fetch a venue-aware funding analysis and verify whether Binance is actually present.
  const analysis = await callMcpSkill({
    toolId,
    toolName: "get_funding_analysis",
    args: { coin: "ETH" }
  });

  const currentFunding = analysis && typeof analysis.currentFunding === "object" && analysis.currentFunding
    ? analysis.currentFunding
    : {};

  const hyperliquidFunding =
    typeof currentFunding.hyperliquid === "number"
      ? currentFunding.hyperliquid
      : typeof currentFunding.Hyperliquid === "number"
        ? currentFunding.Hyperliquid
        : null;

  const binanceFunding =
    typeof currentFunding.binance === "number"
      ? currentFunding.binance
      : typeof currentFunding.Binance === "number"
        ? currentFunding.Binance
        : null;

  const hasHyperliquid = typeof hyperliquidFunding === "number";
  const hasBinance = typeof binanceFunding === "number";

  // Decide: only compute the spread if both venue-specific values are explicitly present.
  const fundingSpread =
    hasHyperliquid && hasBinance ? hyperliquidFunding - binanceFunding : null;

  const arbitrageSpreadRightNow =
    fundingSpread !== null ? fundingSpread !== 0 : null;

  return {
    coin: analysis?.coin ?? "ETH",
    fetchedAt: analysis?.fetchedAt ?? null,
    dataFreshness: analysis?.dataFreshness ?? null,
    probe: {
      hyperliquidFunding,
      binanceFunding,
      hasHyperliquid,
      hasBinance
    },
    fundingSpread,
    arbitrageSpreadRightNow,
    fundingArbitrage: analysis?.fundingArbitrage ?? null,
    missingData: {
      binanceQueryVerified: hasBinance,
      stopReason: hasBinance
        ? null
        : "Binance funding was not explicitly returned by the venue-aware analysis, so no funding-arbitrage conclusion can be made."
    }
  };
}

